INSERT INTO daily_questions (question, answer, date, like_count, comment_count, view_count, status, created_at, updated_at) VALUES
('什么是最好的编程语言？', '没有最好的编程语言，只有最适合的场景。Python 适合数据科学和快速原型开发；JavaScript 适合 Web 前端和全栈；Go 适合高并发后端服务和云原生基础设施；Rust 适合系统编程和对性能与安全要求极高的场景；Java 适合企业级大型项目；C++ 适合游戏引擎和高性能计算。选择语言时更多考虑团队熟悉度、生态成熟度、招聘难度而非语言本身优劣。', '2026-06-20', 42, 8, 156, 1, NOW(), NOW()),
('如何成为一名优秀的软件工程师？', '成为优秀软件工程师没有捷径：1. 打好计算机基础：数据结构、算法、操作系统、网络、数据库；2. 保持持续学习：每月读一本技术书，每周至少学一个新概念；3. 多写代码多练手：LeetCode 保持手感，业余写开源项目；4. 多读优秀源码：学习语言标准库、知名框架如 Gin、Redis 的源码；5. 参与开源社区：从修 Bug、写文档开始，到贡献 Feature；6. 提升软技能：写作能力、演讲分享、跨团队沟通。5年为周期坚持必见效果。', '2026-06-19', 128, 15, 234, 1, NOW(), NOW()),
('远程办公的优缺点是什么？', '远程办公优点：1. 时间完全自主，可根据状态调节工作时段；2. 省去每天1-2小时通勤，多出的时间可用于生活或学习；3. 居住选择自由，不需要待在高房价的一线城市；4. 工作环境舒适，有宠物陪伴减少压力。缺点：1. 缺乏面对面沟通，容易有信息差和误解；2. 自制力差的人容易摸鱼，家庭和工作边界模糊；3. 新人融入团队和晋升受影响（面对面印象加分）；4. 同事社交少，容易孤独。建议采用「混合办公」模式：每周2-3天去办公室，其余远程。', '2026-06-18', 89, 12, 189, 1, NOW(), NOW()),
('如何看待人工智能的发展？', '人工智能是不可逆的技术趋势，我们应该：1. 拥抱而非抗拒：主动学习使用 AI 工具提高效率，如同当年学习使用 Google 和 IDE；2. 保持独立思考：AI 生成的内容要自己验证，不盲信复制；3. 专注人类独有优势：创造力、审美品味、业务理解、跨领域整合、人际沟通领导力；4. 关注 AI 伦理：数据隐私保护、算法偏见、版权归属、AI 内容标识都是需要重视的议题；5. 保持长期学习：不需要什么都学，但要对关键概念（RAG、Agent、Fine-tuning）理解到位。', '2026-06-17', 234, 28, 456, 1, NOW(), NOW()),
('程序员应该读哪些书？', '程序员必读清单分三个层次：【基础必看】《代码大全》（代码质量圣经）、《深入理解计算机系统》CSAPP（理解底层原理）、《算法导论》或《算法》第四版（数据结构基础）、《设计模式》GoF（复用设计经验）、《重构》（改善既有代码）、《人月神话》（软件工程经典40年不朽）；【进阶提升】《代码整洁之道》《领域驱动设计》DDD、《设计数据密集型应用》DDIA（分布式系统必读）、《深入理解Linux内核》（做底层必读）；【非技术拓展】《思考快与慢》（思维方式）、《金字塔原理》（写作表达）、《非暴力沟通》（团队协作）。每年精读3本基础 + 2本非技术，5年读完必成大器。', '2026-06-16', 156, 19, 312, 1, NOW(), NOW()),
('如何高效学习新技术？', '高效学习的五个方法论：1. 明确目标驱动：不要漫无目的地学，先问「学这个解决什么具体问题？」比如要做博客后端才去学 Gin，而不是听说 Gin 火就去看；2. 边学边练实践第一：文档看到1/3就去动手写 Demo，遇到问题倒查文档比看完记不住强10倍；3. 输出倒逼输入：学完马上写博客总结，或者在团队内做分享给别人讲，讲得清楚才是真学会；4. 间隔重复复习：用 Anki 记录知识点卡片，第1天、第3天、第7天、第30天复习，形成长期记忆；5. 不要同时学太多：每次聚焦一个技术栈，1-2个月搞定再下一个，避免样样通样样松。', '2026-06-15', 198, 22, 378, 1, NOW(), NOW()),
('工作三年该达到什么水平？', '工作三年的软件工程师（高级工程师水平）应该具备：【技术能力】1. 能独立设计并开发中型模块/系统，考虑边界、异常、扩展性；2. 理解常见设计模式和架构原则（KISS、DRY、SOLID）；3. 对所在领域技术栈有深度掌握，比如后端要懂数据库索引优化、缓存策略、MQ 选型；【工程素养】4. 代码质量：写的代码别人接手不骂娘，注释文档齐全；5. 工程意识：会写单元测试、会做 Code Review、懂发布流程和回滚；【软技能】6. 能拆解需求、评估工时、识别风险，不会一拍脑袋说「一周搞定」然后延期一个月；7. 能带1-2个初级工程师：Review 他们的代码，回答问题，帮他们成长；8. 明确技术方向：比如「后端分布式方向」「前端工程化方向」，而不是什么都懂一点但都不深。对照看看自己还差什么？', '2026-06-14', 267, 31, 423, 1, NOW(), NOW()),
('如何保持工作与生活的平衡？', '工作生活平衡不是「两边各50%时间」的完美分割，而是动态的、有节奏的张弛有度。具体建议：1. 划清边界：设定明确下班时间（比如晚7点后关电脑不看工作消息），不要把工作带回家；2. 学会拒绝：不合理的需求、没必要的会议、不属于你的工作要礼貌但坚定地说不，先保护好自己核心产出的时间；3. 培养工作外爱好：跑步、健身、做饭、乐器、看书……任何和屏幕无关的爱好都行，让大脑切换模式；4. 规律运动：每周至少3次30分钟运动，身体是精力的根本，程序员的颈椎腰椎更需要保护；5. 高质量陪伴：和家人朋友在一起时放下手机，专心说话专心吃饭，人在心不在等于白陪；6. 定期休假：别等「忙完这段」，永远忙不完，强制自己每季度休个短假回血；7. 接受不完美：偶尔加班很正常，偶尔没陪家人也没关系，不用因为某一天失衡而自责，长期维度看整体平衡就行。', '2026-06-13', 134, 16, 267, 1, NOW(), NOW()),
('技术选型时应该考虑什么？', '技术选型不是选「最酷最火的」，而是选「最合适团队和业务的」。五个核心决策维度：1. 【团队能力】团队对哪个技术熟悉度最高？学习成本多久能收回？强行用新技术赶项目等于作死；2. 【生态成熟度】社区活跃度（看 GitHub Stars、Issue 响应速度）、周边库是否齐全、踩坑资料多不多、招聘人才难度大不大；3. 【性能与扩展性】目前业务量1000 QPS，但一年后会到多少？现在选的方案能扛到什么规模？是否有平滑升级路径；4. 【商业支持与稳定度】是大厂维护还是个人维护？有没有 LTS 长期支持版本？历史稳定性怎样，会不会半年停更；5. 【长期维护成本】部署复杂度、监控告警是否完善、调试排错难度、升级成本高不高。最后记住：**过早优化是万恶之源，技术选型永远优先选团队最熟的，而不是社区最火的。**', '2026-06-12', 145, 18, 289, 1, NOW(), NOW()),
('单体架构 vs 微服务，怎么选？', '不是所有项目都需要微服务！康威定律说「系统架构 = 团队沟通结构」，先看团队再选架构。选择判断矩阵：【团队规模】5人以下小团队 → 单体架构优先，5-10人团队 → 模块化单体（Modular Monolith），10人以上分多个业务小组 → 再考虑微服务；【业务复杂度】CRUD为主的简单业务、早期产品快速验证 → 单体；业务域边界清晰、不同模块性能差异大（比如计算密集型和IO密集型）→ 微服务；【可扩展性需求】流量平稳、峰值差不超过10倍 → 单体；有明显的波峰波谷、需要按模块弹性伸缩（比如大促只扩订单服务）→ 微服务；【运维能力】有没有专门的 DevOps/平台团队？没有的话，微服务的服务发现、链路追踪、分布式事务、灰度发布能把小团队拖死。90%的情况下，一个「模块化做得好的单体」比「拆分稀烂的微服务」好100倍。微服务不是银弹，是有代价的架构升级。', '2026-06-11', 178, 24, 345, 1, NOW(), NOW()),
('如何写出优雅的代码？', '优雅代码是写给人看的，顺便给机器执行。六个原则：1. 【命名即文档】变量、函数、类名要「见名知意」，不要用缩写不要拼音：`userCreatedAt` 比 `uc` 好一万倍；布尔值用 is/has/should 前缀：`isEnabled` 不是 `enable`；2. 【函数短小职责单一】每个函数做一件事，20行以内最佳；超过50行就要想能不能拆；3. 【注释写 Why 不写 What】好代码本身说明 What，注释只解释「为什么这么写」（业务背景、历史原因、踩过的坑）；不要写 `i++  // 把i加1` 这种废话；4. 【适当留白】逻辑段落之间空一行，像写文章分段落；不要所有代码挤在一起；5. 【异常处理完善】不要吞错误（`if err != nil { return nil }` 隐藏问题），不要用 panic 处理业务错误；错误要带上下文方便排查；6. 【及时重构】《重构》说「三次法则」：第一次写是理所当然，第二次类似代码还能忍，第三次出现类似逻辑——必须重构抽象出来。记住一句话：**任何傻瓜都能写出计算机能理解的代码，优秀程序员写出人类能理解的代码。**', '2026-06-10', 212, 27, 389, 1, NOW(), NOW()),
('数据库索引的设计原则？', '合理的索引是数据库性能优化的第一道防线。五个设计原则：1. 【优先级顺序】WHERE 条件列 > ORDER BY 排序列 > GROUP BY 分组列 > JOIN 关联列。SELECT 的列不需要建索引；2. 【高区分度优先】性别、状态这种只有2-3个值的列建索引几乎没用，要选区分度高的列（用户ID、手机号、唯一业务编码等）。区分度 = COUNT(DISTINCT col) / COUNT(*)，>0.3 才值得建；3. 【联合索引最左前缀】建 `(a, b, c)` 联合索引，相当于有了 `(a)`、`(a, b)`、`(a, b, c)` 三个索引。把最常查询的列放最左边；范围查询列（BETWEEN、<、>）放最后，否则范围后面的索引用不上；4. 【控制索引数量】索引不是越多越好：每个索引占磁盘空间，INSERT/UPDATE/DELETE 时索引都要维护，写操作变慢。一般一张表索引不超过 5 个，写多读少的表尽量少建；5. 【避免冗余和重复】有了 `(a, b)` 就不要单独再建 `(a)` 了（除非只查 a 的场景非常多且查询量巨大）。定期用 `sys.schema_unused_indexes` 查无用索引删掉。最后别忘了：建完索引一定要用 EXPLAIN 验证，看实际用没用上，Type 字段至少要到 range 级别，ALL 全表扫描要尽量消灭。', '2026-06-09', 156, 14, 278, 1, NOW(), NOW()),
('如何准备技术面试？', '技术面试不是考你「平时会什么」，而是考你「面试那几个小时能展示什么」，所以一定要系统准备。五部分清单：1. 【算法与数据结构】目标：LeetCode 中等难度 200+ 道，按题型分类刷：数组/字符串 → 链表 → 树/BFS/DFS → 动态规划 → 回溯/贪心；高频题型：二分、滑动窗口、前缀和、单调栈必须熟练；每天2-3道保持手感，面试前1个月冲刺；2. 【计算机基础】操作系统：进程/线程/协程区别、内存管理分页分段、死锁条件、IO模型（BIO/NIO/IO多路复用）；网络：TCP三次握手四次挥手、TIME_WAIT/CLOSE_WAIT原因、TCP/UDP区别、HTTP/HTTPS/HTTP2.0/HTTP3、DNS解析流程；数据库：MySQL索引原理B+树、事务ACID、MVCC实现、隔离级别与问题、锁机制、Redis 五种结构底层实现和适用场景；3. 【项目深度梳理】STAR法则准备每个项目：S(情境)、T(任务)、A(行动)、R(结果)；一定要准备好三个问题的深度答案：「项目中最大的技术挑战是什么？怎么解决的？」「如果重来一次，这个项目你会怎么改进架构？」「项目中XX设计为什么选A方案不选B方案？」；4. 【系统设计能力】（中高级必考）了解常见系统的设计套路：短链接、秒杀、排行榜、Feed流、聊天系统、限流/熔断/降级设计；重点是思路而非细节：需求澄清 → 容量估算 → 组件选择 → 架构图 → 瓶颈分析 → 优化方案；5. 【模拟面试练习】找朋友一起模拟，录下来自己回看，会发现很多口语化、啰嗦、逻辑混乱的问题；面试前一天把自我介绍、项目介绍稿子写好背熟，不打无准备之仗。记住：技术面试=70%实力+30%表达，展示不出来等于不会。', '2026-06-08', 321, 35, 512, 1, NOW(), NOW()),
('程序员如何建立个人品牌？', '个人品牌不是「成为网红」，而是在你的圈子里「提到某个领域就能想到你」。对程序员来说，这比简历上的名校大厂更有力量。五个落地方法：1. 【坚持写技术博客】这是性价比最高、门槛最低的方式：每解决一个问题、每学一个技术，就把过程记录下来。不需要是完美教程，真实的踩坑记录、Debug 过程反而更受欢迎。平台：掘金、知乎专栏、个人博客同步发，每周至少1篇，坚持1年必有效果；2. 【参与开源项目】从「用开源」进阶到「贡献开源」。步骤：先给自己常用的项目提 Issue 报 Bug → 修小 Bug 改文档发第一个 PR → 慢慢参与 Feature 讨论 → 成为 Contributor 再到 Committer。GitHub 贡献记录是最好的隐形简历；3. 【技术社区活跃】掘金/知乎/InfoQ 认真回答问题，不要灌水；GitHub 用心写 Issue 和 PR 评论，写得好的回复别人会点进你主页看；Twitter/X 上多分享英文技术内容，国际大 V 转一次涨粉几百；4. 【做技术分享】公司内 Tech Talk、本地 GDG 技术沙龙、线上直播 B站录课。输出一次比输入十次理解更深刻，还能认识同好。别怕讲得不好，讲十次自然就顺了；5. 【长期主义复利效应】个人品牌的积累是指数曲线：前半年可能没人看、没涨粉，坚持两年后量变到质变，机会会主动来找你。最后核心提醒：**个人品牌的根基永远是「真才实学」**，没有实力的人设会塌。先把事做好，再把做的事说出来。', '2026-06-07', 187, 21, 356, 1, NOW(), NOW()),
('学习算法有什么用？', '很多程序员觉得「工作中又不会自己写红黑树，学算法没用」，这是认知误区。学习算法的五个核心价值：1. 【提升编程思维能力】算法训练的本质是「把复杂问题拆解成可执行步骤的能力」——这是编程的元能力，和语言无关。刷过 300 道 LeetCode 的人，写业务代码时对边界条件、时间空间复杂度的敏感度，和完全没刷过的人不是一个量级；2. 【技术面试的敲门砖】大厂面试算法是标配，不是因为工作真的要用动态规划，而是因为算法题能在短时间内客观衡量一个人的逻辑思维、代码熟练度和抗压能力。想去好公司，算法刷题是绕不过的性价比最高的路径；3. 【理解底层技术原理】所有你每天用的技术，底层都是算法：MySQL 索引用 B+ 树、Redis 跳表、Linux CFS 调度用红黑树、Nginx LRU 缓存淘汰、TCP 拥塞控制……不懂算法你只能停留在「调包侠」层面，遇到性能问题根本无从下手；4. 【写出更高性能的代码】写循环的时候你会注意：这是 O(n²) 还是 O(n)？数据量大了会不会超时？会选择用 map 还是 for 循环查找？不会学完算法写出慢到离谱的代码还自我感觉良好；5. 【锻炼大脑保持敏锐】解算法题和做数学题、下棋一样，是纯粹的脑力体操，长期坚持思维清晰，不容易被 AI 替代。推荐学习路径：《算法》第四版入门 → LeetCode HOT 100 → 按标签分类刷到 200 道中等 → 周赛保持全国前 20%。不求成为竞赛选手，但基本功必须扎实。', '2026-06-06', 167, 19, 298, 1, NOW(), NOW()),
('如何管理每天的时间？', '时间管理的本质不是「把每分钟填满」，而是「把时间花在真正重要的事上」。亲测有效的六个方法：1. 【每日三件大事 MIT】每天早上到公司第一件事：写下今天必须完成的 3 件最重要的事（Most Important Things）。不是 5 件不是 10 件，就 3 件！做完这 3 件，今天就算成功，剩下的时间都是赚的；2. 【番茄工作法防打断】25 分钟专注 + 5 分钟休息 = 1 个番茄钟。专注期间手机调勿扰、关通知、不开新网页。复杂工作用 90 分钟「深度工作块」：上午、下午各留一块，期间不回消息不接电话；3. 【批量处理邮件消息】不要消息一响就回——这是时间碎片化的元凶！固定时间处理：上午10:30、下午3:30、下班前各处理一次消息和邮件，每次 15 分钟，其他时间专注做核心工作；4. 【拒绝无效会议】开会前先问：「这个会我必须参加吗？有我需要决策或输出的内容吗？」两者都没有就礼貌请假，要求看会议纪要就行；开会必须有议程和时间限制，超过一小时的会大概率是浪费时间；5. 【建立时间日志】写一周的时间开销日志：每半小时记一下自己干了啥。你会震惊地发现：真正的有效工作时间可能只有 3 小时，剩下的都在刷手机、闲聊、摸鱼。先知道时间去哪了，才能优化；6. 【定期复盘迭代】每周日晚上花 30 分钟做「时间复盘」：本周 MIT 完成率多少？时间最大的黑洞是什么？下周哪一块要优化？时间管理像健身，不是学完理论就有好身材，要不断实践和调整。推荐入门书：《高效能人士的七个习惯》《深度工作》《番茄工作法图解》。', '2026-06-05', 145, 17, 267, 1, NOW(), NOW());
